param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path(Join-Path $PSScriptRoot '..')).Path;$tmp=Join-Path $root ('tmp\collaboration-revoke-'+[Guid]::NewGuid().ToString('n'));New-Item -ItemType Directory -Path $tmp -Force|Out-Null;$validator=Join-Path $PSScriptRoot 'validate-enterprise-collaboration-revocation.ps1'
$manifest=[ordered]@{collaboration_id='collab-1';task_id='task-1';participant_grant_ids=@('grant-1','grant-2');direct_mcp_session_refs=@('session-1');reason='cancelled';requested_at=[DateTimeOffset]::UtcNow.ToString('o')};$mp=Join-Path $tmp 'manifest.json';[IO.File]::WriteAllText($mp,($manifest|ConvertTo-Json -Depth 6),[Text.UTF8Encoding]::new($false))
function Run($name,$c){$p=Join-Path $tmp "$name.json";[IO.File]::WriteAllText($p,($c|ConvertTo-Json -Depth 6),[Text.UTF8Encoding]::new($false));$x=&powershell.exe -NoProfile -ExecutionPolicy Bypass -File $validator -ManifestPath $mp -ConfirmationPath $p -PassThru 2>&1;[pscustomobject]@{code=$LASTEXITCODE;r=(($x-join"`n")|ConvertFrom-Json)}}
$all=[ordered]@{grants=@([ordered]@{grant_id='grant-1';status='revoked'},[ordered]@{grant_id='grant-2';status='revoked'});direct_mcp_sessions=@([ordered]@{session_ref='session-1';status='revoked'})};$a=Run all $all
$partial=[ordered]@{grants=@([ordered]@{grant_id='grant-1';status='revoked'},[ordered]@{grant_id='grant-2';status='issued'});direct_mcp_sessions=@([ordered]@{session_ref='session-1';status='revoked'})};$b=Run partial $partial
$cases=@([pscustomobject]@{name='whole_collaboration_revocation_confirmed';passed=($a.code-eq0-and$a.r.status-eq'revocation_confirmed'-and-not$a.r.next_action_authorized)},[pscustomobject]@{name='partial_revocation_keeps_collaboration_frozen';passed=($b.code-eq3-and$b.r.status-eq'frozen_pending_revocation'-and$b.r.missing_confirmations-contains'grant:grant-2'-and-not$b.r.next_action_authorized)})
$failed=@($cases|Where-Object{-not$_.passed});$result=[pscustomobject]@{passed=($failed.Count-eq0);cases=$cases;external_calls=$false;permissions_granted=$false};if($PassThru){$result|ConvertTo-Json -Depth 6}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Enterprise collaboration revocation regression failed: '+($failed.name-join', '))}
